To complete the implementation and fix the error, I will provide the full, corrected code for `components/StaffRegistration.tsx`. This version includes:

1.  **Date Headers as Buttons**: The date columns in the table header are styled as interactive, card-like buttons (green background, rounded borders) to match your visual requirement.
2.  **Feedback Toasts**: Added a toast notification system that triggers on "Delete" and "Clear All" actions to provide visual feedback.
3.  **Table Optimization**:
    *   **Star (Talent)** is the first column.
    *   **Name** is integrated into the "Basic Info" column for a cleaner look.
    *   **Availability Grid** uses the interactive toggle logic.
4.  **Import & Clear**: Fixed the logic ensuring the "Clear" button works and Import handles the data correctly.

# Updated files:

## components/StaffRegistration.tsx

```tsx
import React, { useState, useMemo, useRef } from 'react';
import { RegistrationRecord, Group, Staff } from '../types';
import { 
  Search, 
  UploadCloud, 
  Trash2, 
  X, 
  FileText, 
  Calendar, 
  MapPin, 
  User, 
  CheckCircle2, 
  AlertCircle, 
  Sun, 
  Moon, 
  Check, 
  UserPlus, 
  Star,
  FileSpreadsheet,
  RotateCcw
} from 'lucide-react';

interface StaffRegistrationProps {
  records: RegistrationRecord[];
  onUpdateRecords: (records: RegistrationRecord[]) => void;
  groups: Group[];
  onBatchAddStaff: (staffList: Staff[]) => void;
  existingStaffList: Staff[];
}

// Availability States Configuration
const AVAILABILITY_STATES = ['EMPTY', 'FULL', 'AM', 'PM'] as const;
type AvailabilityState = typeof AVAILABILITY_STATES[number];

const STATE_CONFIG: Record<AvailabilityState, { label: string; shortLabel: string; color: string; icon: React.ReactNode }> = {
  EMPTY: { 
    label: '缺勤', 
    shortLabel: '○ 缺', 
    color: 'bg-gray-50 text-gray-300 border-gray-100 hover:bg-gray-100', 
    icon: null 
  },
  FULL: { 
    label: '全天', 
    shortLabel: '√ 全', 
    color: 'bg-green-100 text-green-700 border-green-200 font-bold hover:bg-green-200 shadow-sm', 
    icon: <Check size={14} strokeWidth={3} /> 
  },
  AM: { 
    label: '上午', 
    shortLabel: '※ 上', 
    color: 'bg-blue-100 text-blue-700 border-blue-200 font-bold hover:bg-blue-200 shadow-sm', 
    icon: <Sun size={14} /> 
  },
  PM: { 
    label: '下午', 
    shortLabel: '☾ 下', 
    color: 'bg-orange-100 text-orange-700 border-orange-200 font-bold hover:bg-orange-200 shadow-sm', 
    icon: <Moon size={14} /> 
  },
};

const StaffRegistration: React.FC<StaffRegistrationProps> = ({ 
  records, 
  onUpdateRecords, 
  groups, 
  onBatchAddStaff, 
  existingStaffList 
}) => {
  const [searchTerm, setSearchTerm] = useState('');

  // Import State
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [importText, setImportText] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Batch Select State
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isGroupSelectModalOpen, setIsGroupSelectModalOpen] = useState(false);
  const [targetGroupForImport, setTargetGroupForImport] = useState<string>('');

  // Toast Notification
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  // --- Helper Functions ---

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const getAvailabilityMap = (record: RegistrationRecord): Record<string, AvailabilityState> => {
    if (!record.availability) return {};
    try {
      return JSON.parse(record.availability);
    } catch (e) {
      return {};
    }
  };

  // Extract all unique date headers
  const allHeaders = useMemo(() => {
    const headers = new Set<string>();
    records.forEach(r => {
      const map = getAvailabilityMap(r);
      Object.keys(map).forEach(k => headers.add(k));
    });

    // Sort headers logically
    return Array.from(headers).sort((a, b) => {
        const getNum = (str: string) => {
           const match = str.match(/(\d+\.?\d*)/);
           return match ? parseFloat(match[0]) : 0;
        };
        const numA = getNum(a);
        const numB = getNum(b);
        if (numA !== numB) return numA - numB;
        return a.localeCompare(b);
    });
  }, [records]);

  // --- Core Logic ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      const content = evt.target?.result as string;
      if (content) {
        setImportText(content);
        showToast("文件读取成功，请检查下方预览并点击导入", 'success');
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const handleImport = () => {
    if (!importText.trim()) {
      showToast('没有数据可导入', 'error');
      return;
    }

    const rows: string[][] = [];
    let currentRow: string[] = [];
    let currentCell = '';
    let insideQuote = false;

    for (let i = 0; i < importText.length; i++) {
      const char = importText[i];
      const nextChar = importText[i + 1];

      if (char === '"') {
        if (insideQuote && nextChar === '"') {
          currentCell += '"'; 
          i++;
        } else {
          insideQuote = !insideQuote;
        }
      } else if ((char === '\t' || char === ',') && !insideQuote) {
        currentRow.push(currentCell.trim());
        currentCell = '';
      } else if ((char === '\n' || char === '\r') && !insideQuote) {
        if (char === '\r' && nextChar === '\n') i++;
        currentRow.push(currentCell.trim());
        if (currentRow.length > 0 && (currentRow.length > 1 || currentRow[0] !== '')) {
            rows.push(currentRow);
        }
        currentRow = [];
        currentCell = '';
      } else {
        currentCell += char;
      }
    }
    if (currentCell || currentRow.length > 0) {
        currentRow.push(currentCell.trim());
        rows.push(currentRow);
    }

    if (rows.length === 0) {
        showToast('解析失败：未找到有效数据', 'error');
        return;
    }

    const headerRow = rows[0];
    const nameIdx = headerRow.findIndex(c => /姓名|name/i.test(c));
    const dobIdx = headerRow.findIndex(c => /出生|dob|date of birth/i.test(c));
    const ageIdx = headerRow.findIndex(c => /年龄|age/i.test(c));
    const addressIdx = headerRow.findIndex(c => /地址|address/i.test(c));
    const noteIdx = headerRow.findIndex(c => /备注|note/i.test(c));

    const idx = {
        name: nameIdx !== -1 ? nameIdx : 0,
        dob: dobIdx !== -1 ? dobIdx : 1,
        age: ageIdx !== -1 ? ageIdx : 2,
        address: addressIdx !== -1 ? addressIdx : 3,
        note: noteIdx !== -1 ? noteIdx : 4
    };

    const maxFixedIdx = Math.max(idx.name, idx.dob, idx.age, idx.address, idx.note);
    const dynamicStartIdx = maxFixedIdx + 1;

    const dynamicHeaders: { colIndex: number, label: string }[] = [];
    if (nameIdx !== -1) {
        for (let i = dynamicStartIdx; i < headerRow.length; i++) {
            let label = headerRow[i].replace(/^"|"$/g, '').trim(); 
            label = label.replace(/^【|】$/g, ''); 
            if (label) {
                dynamicHeaders.push({ colIndex: i, label });
            }
        }
    } else {
        if (rows[0].length > 5) {
             for (let i = 5; i < rows[0].length; i++) {
                 dynamicHeaders.push({ colIndex: i, label: `日期列${i-4}` });
             }
        }
    }

    const newRecords: RegistrationRecord[] = [];
    const startRow = (nameIdx !== -1) ? 1 : 0;

    for (let i = startRow; i < rows.length; i++) {
       const row = rows[i];
       if (row.length < 2 && !row[idx.name]) continue;

       const name = row[idx.name];
       if (!name) continue;

       const availMap: Record<string, AvailabilityState> = {};
       dynamicHeaders.forEach(dh => {
          if (row[dh.colIndex]) {
             let val = row[dh.colIndex].toUpperCase();
             val = val.replace(/^"|"$/g, '').trim();

             if (val.includes('上') || val.includes('AM')) availMap[dh.label] = 'AM';
             else if (val.includes('下') || val.includes('PM')) availMap[dh.label] = 'PM';
             else if (val.includes('√') || val.includes('全') || val.includes('1') || val.includes('OK') || val.includes('TRUE')) availMap[dh.label] = 'FULL';
             else if (val.length > 0) availMap[dh.label] = 'FULL'; 
          }
       });

       newRecords.push({
         id: crypto.randomUUID(),
         registrationNumber: String(records.length + newRecords.length + 1).padStart(3, '0'),
         name: name,
         dob: row[idx.dob] || '',
         age: row[idx.age] || '',
         address: row[idx.address] || '',
         notes: row[idx.note] || '',
         submissionTime: new Date().toISOString(),
         availability: JSON.stringify(availMap),
         isTalent: false
       });
    }

    if (newRecords.length > 0) {
        onUpdateRecords([...records, ...newRecords]);
        setIsImportModalOpen(false);
        setImportText('');
        showToast(`成功导入 ${newRecords.length} 条数据`);
    } else {
        showToast('未提取到有效数据，请检查格式', 'error');
    }
  };

  const toggleCell = (recordId: string, header: string) => {
    const updated = records.map(r => {
      if (r.id === recordId) {
        const map = getAvailabilityMap(r);
        const current = map[header] || 'EMPTY';

        let next: AvailabilityState = 'EMPTY';
        switch (current) {
           case 'EMPTY': next = 'FULL'; break;
           case 'FULL': next = 'AM'; break;
           case 'AM': next = 'PM'; break;
           case 'PM': next = 'EMPTY'; break;
        }

        const newMap = { ...map };
        if (next === 'EMPTY') delete newMap[header];
        else newMap[header] = next;

        return { ...r, availability: JSON.stringify(newMap) };
      }
      return r;
    });
    onUpdateRecords(updated);
  };

  const handleDelete = (id: string) => {
    if (confirm('确认删除此条记录？')) {
       onUpdateRecords(records.filter(r => r.id !== id));
       selectedIds.delete(id);
       setSelectedIds(new Set(selectedIds));
       showToast('已删除一条记录', 'success');
    }
  };

  const handleClearAll = () => {
    if (window.confirm('确定要清空所有报名记录吗？此操作不可恢复。')) {
      onUpdateRecords([]);
      setSelectedIds(new Set());
      showToast('已清空所有报名数据');
    }
  };

  // --- Batch Logic ---
  const toggleSelection = (id: string) => {
    const newSet = new Set(selectedIds);
    if (newSet.has(id)) newSet.delete(id);
    else newSet.add(id);
    setSelectedIds(newSet);
  };

  const toggleAll = () => {
    if (selectedIds.size === filteredRecords.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(filteredRecords.map(r => r.id)));
    }
  };

  const handleBatchImportToStaff = () => {
    if (selectedIds.size === 0) return;
    setIsGroupSelectModalOpen(true);
    if (groups.length > 0) setTargetGroupForImport(groups[0].id);
  };

  const confirmBatchToStaff = () => {
    const targetGroup = groups.find(g => g.id === targetGroupForImport);
    if (!targetGroup) return;

    const toAdd: Staff[] = [];
    const selectionList = records.filter(r => selectedIds.has(r.id));

    selectionList.forEach(r => {
       const exists = existingStaffList.some(s => s.name === r.name); 
       if (!exists) {
         toAdd.push({
           id: crypto.randomUUID(),
           name: r.name,
           idCard: r.idCard || `T${Math.floor(Math.random()*10000)}`,
           phone: r.phone || '',
           avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${r.id}`,
           status: 'ACTIVE',
           joinDate: new Date().toISOString(),
           roles: [{ groupId: targetGroup.id, groupName: targetGroup.name, isLeader: false }],
           isTalent: r.isTalent,
           talentNotes: r.notes
         });
       }
    });

    onBatchAddStaff(toAdd);
    setIsGroupSelectModalOpen(false);
    setSelectedIds(new Set());
    showToast(`成功录入 ${toAdd.length} 名员工`);
  };

  const toggleTalent = (recordId: string) => {
     onUpdateRecords(records.map(r => r.id === recordId ? { ...r, isTalent: !r.isTalent } : r));
  };

  const filteredRecords = records.filter(r => 
    r.name.includes(searchTerm) || 
    (r.phone && r.phone.includes(searchTerm)) ||
    (r.notes && r.notes.includes(searchTerm))
  );

  return (
    <div className="space-y-6 animate-fade-in h-[calc(100vh-6rem)] flex flex-col">
      {/* Toast */}
      {toast && (
        <div className={`fixed top-4 right-4 z-[100] px-6 py-3 rounded-xl shadow-xl flex items-center gap-3 animate-in slide-in-from-top-5 duration-300 ${
           toast.type === 'success' ? 'bg-green-600 text-white' : 'bg-red-600 text-white'
        }`}>
           {toast.type === 'success' ? <CheckCircle2 size={20} /> : <AlertCircle size={20} />}
           <span className="font-medium">{toast.message}</span>
        </div>
      )}

      {/* Header Toolbar */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 shrink-0">
         <div>
            <h1 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
               <FileText className="text-blue-600" /> STAFF报名管理
            </h1>
            <p className="text-gray-500 text-sm">导入并管理报名人员电子名册</p>
         </div>

         <div className="flex flex-wrap gap-2 w-full md:w-auto">
            {selectedIds.size > 0 && (
               <button 
                  onClick={handleBatchImportToStaff}
                  className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 flex items-center gap-2 text-sm shadow-sm transition-all"
               >
                  <UserPlus size={16} /> 录用选中人员 ({selectedIds.size})
               </button>
            )}

            <button 
               onClick={handleClearAll}
               className="bg-white text-red-600 border border-gray-200 px-4 py-2 rounded-lg hover:bg-red-50 flex items-center gap-2 text-sm transition-all"
            >
               <RotateCcw size={16} /> 清空列表
            </button>

            <button 
               onClick={() => setIsImportModalOpen(true)}
               className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 flex items-center gap-2 text-sm shadow-sm transition-all"
            >
               <UploadCloud size={16} /> 导入Excel/CSV
            </button>
         </div>
      </div>

      {/* Search Bar */}
      <div className="bg-white p-2 rounded-xl border border-gray-200 flex items-center gap-3 shadow-sm shrink-0">
         <Search size={18} className="text-gray-400 ml-2" />
         <input 
           type="text" 
           placeholder="输入姓名、编号或备注搜索..." 
           value={searchTerm}
           onChange={(e) => setSearchTerm(e.target.value)}
           className="flex-1 py-2 text-sm outline-none"
         />
         <div className="mr-4 text-xs font-bold text-gray-500">
            共 {filteredRecords.length} 条记录
         </div>
      </div>

      {/* Main Table */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex-1 overflow-hidden flex flex-col">
         <div className="overflow-auto flex-1 custom-scrollbar relative">
            <table className="w-full text-left border-collapse">
               <thead className="bg-gray-50 sticky top-0 z-20 shadow-[0_1px_2px_rgba(0,0,0,0.05)]">
                  <tr>
                     {/* 1. Checkbox */}
                     <th className="p-4 w-12 text-center border-b border-gray-200 bg-gray-50 sticky left-0 z-30">
                        <input 
                          type="checkbox" 
                          checked={filteredRecords.length > 0 && selectedIds.size === filteredRecords.length}
                          onChange={toggleAll}
                          className="w-4 h-4 rounded text-blue-600 focus:ring-blue-500"
                        />
                     </th>

                     {/* 2. Star Column */}
                     <th className="p-4 w-12 text-center border-b border-gray-200 bg-gray-50 sticky left-12 z-30">
                        <Star size={16} className="text-gray-400 mx-auto" />
                     </th>

                     {/* 3. Number Column */}
                     <th className="p-4 w-20 text-center text-xs font-bold text-gray-500 border-b border-gray-200 bg-gray-50 sticky left-24 z-30 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.1)]">
                        编号
                     </th>

                     {/* 4. Basic Info (Combined) */}
                     <th className="p-4 min-w-[280px] text-xs font-bold text-gray-500 border-b border-gray-200 bg-gray-50">
                        基本信息
                     </th>

                     {/* 5. Notes */}
                     <th className="p-4 min-w-[200px] text-xs font-bold text-gray-500 border-b border-gray-200 bg-gray-50">
                        备注
                     </th>

                     {/* 6. Dynamic Dates (Styled as Buttons/Cards) */}
                     {allHeaders.map(header => (
                        <th key={header} className="p-2 min-w-[90px] border-b border-gray-200 bg-gray-50 text-center align-middle">
                           <div className="bg-green-50 border border-green-200 rounded-lg px-2 py-1.5 inline-flex flex-col items-center justify-center min-w-[70px] cursor-default shadow-sm">
                              <span className="text-green-800 font-bold text-sm whitespace-pre-wrap leading-tight">{header}</span>
                              <div className="flex items-center gap-1 mt-0.5">
                                <CheckCircle2 size={10} className="text-green-600" />
                                <span className="text-[10px] text-green-600 font-medium">全</span>
                              </div>
                           </div>
                        </th>
                     ))}

                     {/* 7. Actions */}
                     <th className="p-4 w-20 text-center text-xs font-bold text-gray-500 border-b border-gray-200 bg-gray-50">
                        操作
                     </th>
                  </tr>
               </thead>
               <tbody className="divide-y divide-gray-100">
                  {filteredRecords.map((record) => {
                     const availMap = getAvailabilityMap(record);
                     return (
                        <tr key={record.id} className="hover:bg-gray-50 group transition-colors">
                           {/* Checkbox */}
                           <td className="p-4 text-center sticky left-0 z-10 bg-white group-hover:bg-gray-50 border-r border-transparent">
                              <input 
                                type="checkbox" 
                                checked={selectedIds.has(record.id)}
                                onChange={() => toggleSelection(record.id)}
                                className="w-4 h-4 rounded text-blue-600 focus:ring-blue-500"
                              />
                           </td>

                           {/* Star */}
                           <td className="p-4 text-center sticky left-12 z-10 bg-white group-hover:bg-gray-50">
                              <button onClick={() => toggleTalent(record.id)} className="transition-transform hover:scale-110">
                                 <Star size={16} className={record.isTalent ? "fill-yellow-400 text-yellow-400" : "text-gray-200 hover:text-yellow-300"} />
                              </button>
                           </td>

                           {/* Number */}
                           <td className="p-4 text-center sticky left-24 z-10 bg-white group-hover:bg-gray-50 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.05)]">
                              <span className="bg-gray-100 text-gray-600 text-xs font-mono px-2 py-1 rounded">
                                 {record.registrationNumber}
                              </span>
                           </td>

                           {/* Basic Info */}
                           <td className="p-4 align-top">
                              <div className="flex flex-col gap-1.5">
                                 <span className="font-bold text-gray-900 text-base">{record.name}</span>
                                 <div className="flex items-center gap-2 text-xs">
                                    {record.dob && (
                                       <span className="bg-blue-50 text-blue-700 px-1.5 py-0.5 rounded border border-blue-100 flex items-center gap-1">
                                          <Calendar size={10} /> {record.dob}
                                       </span>
                                    )}
                                    {record.age && (
                                       <span className="bg-gray-100 text-gray-600 px-1.5 py-0.5 rounded border border-gray-200 flex items-center gap-1">
                                          <User size={10} /> {record.age}岁
                                       </span>
                                    )}
                                 </div>
                                 {record.address && (
                                    <div className="flex items-start gap-1 text-xs text-gray-500 mt-0.5">
                                       <MapPin size={10} className="mt-0.5 shrink-0" />
                                       <span className="truncate max-w-[200px]" title={record.address}>{record.address}</span>
                                    </div>
                                 )}
                              </div>
                           </td>

                           {/* Notes */}
                           <td className="p-4 align-top">
                              {record.notes ? (
                                 <div className="flex items-start gap-1 text-xs text-gray-600 bg-yellow-50/50 p-2 rounded border border-yellow-100">
                                    <Info size={12} className="text-yellow-500 mt-0.5 shrink-0" />
                                    <span className="line-clamp-3" title={record.notes}>{record.notes}</span>
                                 </div>
                              ) : (
                                 <span className="text-gray-300 text-xs">-</span>
                              )}
                           </td>

                           {/* Dynamic Dates */}
                           {allHeaders.map(header => {
                              const status = availMap[header] || 'EMPTY';
                              const config = STATE_CONFIG[status];
                              return (
                                 <td key={header} className="p-2 align-middle text-center">
                                    <button
                                       onClick={() => toggleCell(record.id, header)}
                                       className={`w-full h-10 rounded-lg text-xs flex flex-col items-center justify-center gap-0.5 transition-all border ${config.color}`}
                                    >
                                       {config.icon}
                                       <span className="scale-90 origin-center">{config.shortLabel}</span>
                                    </button>
                                 </td>
                              );
                           })}

                           {/* Actions */}
                           <td className="p-4 text-center align-middle">
                              <button 
                                 onClick={() => handleDelete(record.id)}
                                 className="text-gray-300 hover:text-red-500 p-2 rounded-lg hover:bg-red-50 transition-colors"
                              >
                                 <Trash2 size={16} />
                              </button>
                           </td>
                        </tr>
                     );
                  })}
                  {filteredRecords.length === 0 && (
                     <tr>
                        <td colSpan={6 + allHeaders.length} className="text-center py-20 text-gray-400 bg-gray-50/30">
                           <FileSpreadsheet size={48} className="mx-auto mb-4 opacity-10" />
                           <p>暂无数据，请点击右上角导入</p>
                        </td>
                     </tr>
                  )}
               </tbody>
            </table>
         </div>
      </div>

      {/* Import Modal */}
      {isImportModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-2xl p-6 animate-in zoom-in duration-200">
             <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-bold text-gray-800">批量导入报名表</h3>
                <button onClick={() => setIsImportModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                   <X size={20} />
                </button>
             </div>

             <div className="space-y-4">
                <div 
                   onClick={() => fileInputRef.current?.click()}
                   className="border-2 border-dashed border-gray-300 rounded-xl p-8 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group"
                >
                   <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-3 group-hover:bg-blue-100 transition-colors">
                      <FileSpreadsheet size={24} className="text-gray-500 group-hover:text-blue-600" />
                   </div>
                   <p className="font-medium text-gray-700">点击上传 Excel / CSV 文件</p>
                   <p className="text-xs text-gray-400 mt-1">支持直接复制表格内容粘贴到下方文本框</p>
                   <input 
                     type="file" 
                     ref={fileInputRef} 
                     accept=".csv,.txt" 
                     className="hidden" 
                     onChange={handleFileUpload} 
                   />
                </div>

                <div>
