                              <div className="flex items-center gap-1 mt-0.5">
                                <CheckCircle2 size={10} className="text-green-600" />
                                <span className="text-[10px] text-green-600 font-medium">全</span>
                              </div>

                              {/* Delete Header Button */}
                              <button 
                                onClick={(e) => { e.stopPropagation(); handleDeleteColumn(header); }}
                                className="absolute -top-1.5 -right-1.5 bg-white border border-red-100 text-red-400 rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-50 hover:text-red-600 shadow-sm"
                                title="删除此列"
                              >
                                 <X size={10} />
                              </button>
                           </div>
                        </th>
                     ))}

                     {/* 8. Actions */}
                     <th className="p-4 w-20 text-center text-xs font-bold text-gray-500 border-b border-gray-200 bg-gray-50">
                        操作
                     </th>
                  </tr>
               </thead>
               <tbody className="divide-y divide-gray-100">
                  {filteredRecords.map((record) => {
                     const availMap = getAvailabilityMap(record);
                     return (
                        <tr key={record.id} className="hover:bg-gray-50 group transition-colors">
                           {/* Checkbox */}
                           <td className="p-4 text-center sticky left-0 z-10 bg-white group-hover:bg-gray-50 border-r border-transparent">
                              <input 
                                type="checkbox" 
                                checked={selectedIds.has(record.id)}
                                onChange={() => toggleSelection(record.id)}
                                className="w-4 h-4 rounded text-blue-600 focus:ring-blue-500"
                              />
                           </td>

                           {/* Star */}
                           <td className="p-4 text-center sticky left-12 z-10 bg-white group-hover:bg-gray-50">
                              <button onClick={() => toggleTalent(record.id)} className="transition-transform hover:scale-110">
                                 <Star size={16} className={record.isTalent ? "fill-yellow-400 text-yellow-400" : "text-gray-200 hover:text-yellow-300"} />
                              </button>
                           </td>

                           {/* Number */}
                           <td className="p-4 text-center sticky left-24 z-10 bg-white group-hover:bg-gray-50 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.05)]">
                              <span className="bg-gray-100 text-gray-600 text-xs font-mono px-2 py-1 rounded">
                                 {record.registrationNumber}
                              </span>
                           </td>

                           {/* Name - Centered */}
                           <td className="p-4 text-center">
                              <span className="font-bold text-gray-900 text-base">{record.name}</span>
                           </td>

                           {/* Basic Info */}
                           <td className="p-4 align-top">
                              <div className="flex flex-col gap-1.5">
                                 <div className="flex items-center gap-2 text-xs">
                                    {record.dob && (
                                       <span className="bg-blue-50 text-blue-700 px-1.5 py-0.5 rounded border border-blue-100 flex items-center gap-1">
                                          <Calendar size={10} /> {record.dob}
                                       </span>
                                    )}
                                    {record.age && (
                                       <span className="bg-gray-100 text-gray-600 px-1.5 py-0.5 rounded border border-gray-200 flex items-center gap-1">
                                          <User size={10} /> {record.age}岁
                                       </span>
                                    )}
                                 </div>
                                 {record.address && (
                                    <div className="flex items-start gap-1 text-xs text-gray-500 mt-0.5">
                                       <MapPin size={10} className="mt-0.5 shrink-0" />
                                       <span className="truncate max-w-[200px]" title={record.address}>{record.address}</span>
                                    </div>
                                 )}
                              </div>
                           </td>

                           {/* Notes */}
                           <td className="p-4 align-top">
                              {record.notes ? (
                                 <div className="flex items-start gap-1 text-xs text-gray-600 bg-yellow-50/50 p-2 rounded border border-yellow-100">
                                    <Info size={12} className="text-yellow-500 mt-0.5 shrink-0" />
                                    <span className="line-clamp-3" title={record.notes}>{record.notes}</span>
                                 </div>
                              ) : (
                                 <span className="text-gray-300 text-xs">-</span>
                              )}
                           </td>

                           {/* Dynamic Dates */}
                           {allHeaders.map(header => {
                              const status = availMap[header] || 'EMPTY';
                              const config = STATE_CONFIG[status];
                              return (
                                 <td key={header} className="p-2 align-middle text-center">
                                    <button
                                       onClick={() => toggleCell(record.id, header)}
                                       className={`w-full h-10 rounded-lg text-xs flex flex-col items-center justify-center gap-0.5 transition-all border ${config.color}`}
                                    >
                                       {config.icon}
                                       <span className="scale-90 origin-center">{config.shortLabel}</span>
                                    </button>
                                 </td>
                              );
                           })}

                           {/* Actions */}
                           <td className="p-4 text-center align-middle">
                              <button 
                                 onClick={() => handleDelete(record.id)}
                                 className="text-gray-300 hover:text-red-500 p-2 rounded-lg hover:bg-red-50 transition-colors"
                              >
                                 <Trash2 size={16} />
                              </button>
                           </td>
                        </tr>
                     );
                  })}
                  {filteredRecords.length === 0 && (
                     <tr>
                        <td colSpan={7 + allHeaders.length} className="text-center py-20 text-gray-400 bg-gray-50/30">
                           <FileSpreadsheet size={48} className="mx-auto mb-4 opacity-10" />
                           <p>暂无数据，请点击右上角导入</p>
                        </td>
                     </tr>
                  )}
               </tbody>
            </table>
         </div>
      </div>

      {/* Date Management Modal */}
      {isDateModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
           <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm p-6 animate-in zoom-in duration-200">
              <div className="flex justify-between items-center mb-4">
                 <h3 className="text-lg font-bold text-gray-800">添加排班日期</h3>
                 <button onClick={() => setIsDateModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                    <X size={20} />
                 </button>
              </div>

              <div className="space-y-4">
                 <div className="space-y-2">
                    <label className="text-sm font-medium text-gray-700">开始日期</label>
                    <input 
                      type="date" 
                      value={newDateStart}
                      onChange={e => setNewDateStart(e.target.value)}
                      className="w-full border border-gray-300 rounded-lg p-2 text-sm outline-none focus:ring-2 focus:ring-green-500"
                    />
                 </div>
                 <div className="space-y-2">
                    <label className="text-sm font-medium text-gray-700">结束日期 (可选)</label>
                    <input 
                      type="date" 
                      value={newDateEnd}
                      onChange={e => setNewDateEnd(e.target.value)}
                      className="w-full border border-gray-300 rounded-lg p-2 text-sm outline-none focus:ring-2 focus:ring-green-500"
                      min={newDateStart}
                    />
                 </div>
                 <p className="text-xs text-gray-500 bg-gray-50 p-2 rounded border border-gray-100">
                    * 将批量添加从开始到结束日期之间的所有天数作为新列。
                 </p>
              </div>

              <div className="mt-6 flex justify-end gap-3">
                 <button 
                    onClick={() => setIsDateModalOpen(false)}
                    className="px-4 py-2 text-gray-600 bg-gray-100 rounded-lg hover:bg-gray-200 text-sm font-medium"
                 >
                    取消
                 </button>
                 <button 
                    onClick={handleAddDates}
                    disabled={!newDateStart}
                    className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 text-sm font-medium disabled:opacity-50 flex items-center gap-2"
                 >
                    <Plus size={16} /> 确认添加
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* Import Modal */}
      {isImportModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-2xl p-6 animate-in zoom-in duration-200">
             <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-bold text-gray-800">批量导入报名表</h3>
                <button onClick={() => setIsImportModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                   <X size={20} />
                </button>
             </div>

             <div className="space-y-4">
                <div 
                   onClick={() => fileInputRef.current?.click()}
                   className="border-2 border-dashed border-gray-300 rounded-xl p-8 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group"
                >
                   <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-3 group-hover:bg-blue-100 transition-colors">
                      <FileSpreadsheet size={24} className="text-gray-500 group-hover:text-blue-600" />
                   </div>
                   <p className="font-medium text-gray-700">点击上传 Excel / CSV 文件</p>
                   <p className="text-xs text-gray-400 mt-1">支持直接复制表格内容粘贴到下方文本框</p>
                   <input 
                     type="file" 
                     ref={fileInputRef} 
                     accept=".csv,.txt" 
                     className="hidden" 
                     onChange={handleFileUpload} 
                   />
                </div>

                <div>
                   <label className="text-xs font-bold text-gray-500 uppercase mb-2 block">或直接粘贴文本数据</label>
                   <textarea 
                      value={importText}
                      onChange={(e) => setImportText(e.target.value)}
                      className="w-full h-40 border border-gray-200 rounded-lg p-3 text-xs font-mono focus:ring-2 focus:ring-blue-500 outline-none resize-none bg-gray-50"
                      placeholder={`姓名\t出生日期\t年龄\t地址\t备注\t5.1\t5.2\n张三\t2000.01.01\t24\t广州\t有经验\t√\t√`}
                   />
                </div>

                <div className="bg-blue-50 p-3 rounded-lg border border-blue-100 text-xs text-blue-700 space-y-1">
                   <p className="font-bold flex items-center gap-1"><Info size={12} /> 格式说明</p>
                   <p>1. 系统会自动识别"姓名"、"出生日期"、"年龄"、"地址"、"备注"列。</p>
                   <p>2. <span className="font-bold">备注列之后</span>的所有列，都会被识别为日期表头。</p>
                   <p>3. 单元格内容：支持 '√'、'1'、'全' (全天), '上' (上午), '下' (下午)。</p>
                </div>
             </div>

             <div className="mt-6 flex justify-end gap-3">
                <button 
                   onClick={() => setIsImportModalOpen(false)}
                   className="px-4 py-2 text-gray-600 bg-gray-100 rounded-lg hover:bg-gray-200 font-medium text-sm"
                >
                   取消
                </button>
                <button 
                   onClick={handleImport}
                   className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 font-medium text-sm shadow-sm"
                >
                   确认解析导入
                </button>
             </div>
          </div>
        </div>
      )}

      {/* Group Select Modal */}
      {isGroupSelectModalOpen && (
         <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm p-6 animate-in zoom-in duration-200">
               <h3 className="text-lg font-bold text-gray-800 mb-4">选择录入分组</h3>
               <p className="text-sm text-gray-500 mb-4">将选中的 {selectedIds.size} 人录入到正式员工库中：</p>

               <div className="space-y-3 mb-6">
                  {groups.length === 0 ? (
                     <p className="text-red-500 text-sm">请先在编外管理中创建分组</p>
                  ) : (
                     <select 
                       value={targetGroupForImport} 
                       onChange={(e) => setTargetGroupForImport(e.target.value)}
                       className="w-full border border-gray-300 rounded-lg p-2.5 text-sm outline-none focus:ring-2 focus:ring-indigo-500"
                     >
                        {groups.map(g => (
                           <option key={g.id} value={g.id}>{g.name}</option>
                        ))}
                     </select>
                  )}
               </div>

               <div className="flex justify-end gap-3">
                  <button 
                     onClick={() => setIsGroupSelectModalOpen(false)}
                     className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg text-sm font-medium"
                  >
                     取消
                  </button>
                  <button 
                     onClick={confirmBatchToStaff}
                     disabled={groups.length === 0}
                     className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium disabled:opacity-50"
                  >
                     确认录入
                  </button>
               </div>
            </div>
         </div>
      )}
    </div>
  );
};

export default StaffRegistration;
